mapper.select:
select e.id, e.username, e.password, e.name, e.gender, e.phone, e.exer_type job, e.burn_calorie salary, e.image, e.entry_date, e.location_id deptId, e.create_time, e.update_time, l.name deptName from emp e left join location l on e.location_id = l.id
e.name like concat('%',#{name},'%')
and e.gender = #{gender}
and e.entry_date between #{begin} and #{end}
order by e.update_time desc
